('B', 'specjalistyczne'::question_type, 2, 'Kto ma obowiązek korzystania z pasów bezpieczeństwa?', '{"A": "Tylko kierujący i pasażer siedzący na przednim siedzeniu.", "B": "Kierujący i pasażer - na przednim siedzeniu zawsze, a na tylnym tylko wówczas, gdy pojazd porusza się poza obszarem zabudowanym.", "C": "Kierujący i wszyscy pasażerowie."}'::jsonb, 'C', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/2C103.jpg'),
('B', 'specjalistyczne'::question_type, 2, 'Czy dorosły pasażer samochodu osobowego przewożony na tylnym siedzeniu ma obowiązek używania pasów bezpieczeństwa?', '{"A": "Nie.", "B": "Tak, ale tylko wówczas, gdy pojazd porusza się poza obszarem zabudowanym.", "C": "Tak."}'::jsonb, 'C', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/2C104.jpg'),
('B', 'specjalistyczne'::question_type, 2, 'Czy naruszasz przepisy ruchu drogowego, jeżeli kierując pojazdem rozmawiasz przez telefon trzymając go w ręku?', '{"A": "Nie, pod warunkiem panowania nad pojazdem.", "B": "Nie, pod warunkiem, że telefon trzymam oddalony od ucha z włączonym trybem głośnomówiącym.", "C": "Tak, nawet wówczas gdy telefon trzymam oddalony od ucha z włączonym trybem głośnomówiącym."}'::jsonb, 'C', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/2C105.jpg'),
