('B', 'specjalistyczne'::question_type, 2, 'Ile maksymalnie osób, wliczając siebie, możesz przewozić, gdy masz prawo jazdy kategorii B?', '{"A": "5", "B": "9", "C": "10"}'::jsonb, 'B', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/2C108.jpg'),
('B', 'specjalistyczne'::question_type, 2, 'Na których drogach publicznych masz obowiązek zapinać pasy bezpieczeństwa?', '{"A": "Na wszystkich drogach.", "B": "Tylko na drogach twardych.", "C": "Tylko na drogach poza obszarem zabudowanym."}'::jsonb, 'A', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/2C130.jpg'),
('B', 'specjalistyczne'::question_type, 2, 'Czy wolno Ci przewozić przedszkolaka na kolanach osoby dorosłej?', '{"A": "Tak, tylko na tylnym siedzeniu.", "B": "Nie.", "C": "Tak, jeżeli korzysta się z pasów bezpieczeństwa."}'::jsonb, 'B', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/2C137.jpg'),
('B', 'specjalistyczne'::question_type, 2, 'Czy masz prawo przewozić niemowlaka na kolanach osoby dorosłej?', '{"A": "Nie.", "B": "Tak, ale tylko na tylnym siedzeniu.", "C": "Tak, ale pod warunkiem, że osoba ta korzysta z pasów bezpieczeństwa."}'::jsonb, 'A', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/2C138.jpg'),
('B', 'specjalistyczne'::question_type, 2, 'Jaki jest właściwy sposób przewożenia noworodka samochodem osobowym?', '{"A": "W dowolnym nosidełku, jeśli jest przypięte pasami bezpieczeństwa.", "B": "W odpowiednim dla noworodka foteliku ochronnym.", "C": "Na kolanach osoby dorosłej z zapiętymi pasami bezpieczeństwa."}'::jsonb, 'B', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/2C139.jpg'),
('B1', 'specjalistyczne'::question_type, 2, 'Czy kierując czterokołowcem masz prawo przewozić dziecko w wieku do 6 lat?', '{"A": "Nie.", "B": "Tak, ale tylko z prędkością do 40 km/h.", "C": "Tak, z dowolną prędkością."}'::jsonb, 'B', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/2C160.jpg'),
('B', 'specjalistyczne'::question_type, 2, 'Którym z wymienionych zespołów pojazdów możesz kierować mając prawo jazdy kategorii B?', '{"A": "Samochodem ciężarowym o dopuszczalnej masie całkowitej 2,5 t z przyczepą lekką.", "B": "Ciągnikiem rolniczym z dwiema przyczepami.", "C": "Samochodem osobowym z przyczepą, których łączna dopuszczalna masa całkowita wynosi 4,5 t."}'::jsonb, 'A', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/2C107.jpg'),
